   241→
   242→  useEffect(() => {
   243→    if (!meshRef.current) return;
   244→
   245→    const mesh = meshRef.current;
   246→
   247→    tasks.forEach((task, i) => {
   248→      const width = task.duration * pxPerDay;
   249→      const height = TASK_HEIGHT;
   250→      const x = task.startDay * pxPerDay + width / 2;
   251→      const y = -task.trainIndex * pxPerTrain - pxPerTrain / 2;
   252→      const z = isSelected ? 0.2 : isFocused ? 0.15 : task.hasConflict ? 0.1 : isHovered ? 0.05 : 0;
   253→
   254→      tempObject.position.set(x, y, z);
   255→      tempObject.scale.set(width, height, 1);
   256→      tempObject.updateMatrix();
   257→      mesh.setMatrixAt(i, tempObject.matrix);
   258→
   259→      // Set color based on state
   260→      if (isSelected) {
   261→        tempColor.set(SELECTION_COLOR);
   262→      } else if (isFocused) {
   263→        tempColor.set(FOCUS_COLOR);
   264→      } else if (isHovered) {
   265→        const brightened = brightenColor(baseColor, HOVER_BRIGHTNESS);
   266→        mesh.setColorAt(i, brightened);
