   390→### MOMENTUM ALGORITHM
   391→
   392→```typescript
   393→const startMomentum = useCallback(() => {
   394→  const { vx, vy } = calculateAverageVelocity();
   395→
   396→  canvasStore.dispatch(canvasActions.viewport.startMomentum({
   397→    velocityX: vx * 16, // Convert to world units per frame
   398→    velocityY: vy * 16,
   399→  }));
   400→
   401→  const animate = () => {
   402→    const state = canvasStore.getState();
   403→    const { velocityX, velocityY, isActive } = state.viewport.momentum;
   404→
   405→    if (!isActive) return;
   406→
   407→    // Apply friction
   408→    const newVelX = velocityX * MOMENTUM_FRICTION;
   409→    const newVelY = velocityY * MOMENTUM_FRICTION;
   410→
   411→    // Check velocity threshold
   412→    if (Math.abs(newVelX) < MOMENTUM_MIN_VELOCITY &&
   413→        Math.abs(newVelY) < MOMENTUM_MIN_VELOCITY) {
   414→      canvasStore.dispatch(canvasActions.viewport.stopMomentum());
   415→      return;
   416→    }
   417→
   418→    // Update camera position
   419→    const newCamera = clampCameraToWorld(
   420→      camera.x + newVelX,
   421→      camera.y + newVelY,
   422→      zoom
   423→    );
   424→
   425→    canvasStore.dispatch(canvasActions.viewport.updateMomentum({
   426→      velocityX: newVelX,
   427→      velocityY: newVelY,
   428→      camera: newCamera,
   429→    }));
   430→
   431→    requestAnimationFrame(animate);
   432→  };
   433→
   434→  requestAnimationFrame(animate);
   435→}, []);
   436→```
