   613→## 6. Data Types Architecture
   614→
   615→### Persistent vs Render Types
   616→
   617→**File:** `apps/canvas/src/data/types.ts`
   618→
   619→```typescript
   620→// PERSISTENT - can be serialized to JSON
   621→export interface Task {
   622→  id: string;
   623→  trainId: string;
   624→  startDate: string;       // ISO 8601: "2024-03-15"
   625→  endDate: string;
   626→  type: TaskType;
   627→  hasConflict: boolean;
   628→  predecessorId?: string;  // F023: dependency lines
   629→}
   630→
   631→// RENDER - calculated for canvas
   632→export interface TaskRender {
   633→  id: string;
   634→  trainIndex: number;      // Y position
