## 5. Performance Optimizations

### 5.1 RBush Spatial Index

**File:** `apps/canvas/src/spatial/RBushSpatialIndex.ts`

```typescript
export class RBushSpatialIndex implements ISpatialIndex {
  private tree: RBush<RBushItem>;
  private itemsById: Map<string, RBushItem> = new Map();

  load(items: SpatialItem[]): void {
    const startTime = performance.now();

    this.tree.clear();
    this.itemsById.clear();

    for (const item of items) {
      this.itemsById.set(item.id, item as RBushItem);
    }

    this.tree.load(items as RBushItem[]); // Bulk load is O(n log n)

    // Performance: ~0.5ms for 60k items
  }

  queryViewport(bounds: ViewportBounds): string[] {
    // O(log n + k) where k = result count
    const results = this.tree.search({
      minX: bounds.minX,
      minY: bounds.minY,
      maxX: bounds.maxX,
      maxY: bounds.maxY,
    });

    return results.map(item => item.id);
  }

  queryNearest(x: number, y: number, maxDistance?: number): SpatialQueryResult | null {
    // Expanding radius search
    let radius = 50;
    while (radius <= maxRadius && nearest === null) {
      const candidates = this.tree.search({
        minX: x - radius,
        minY: y - radius,
        maxX: x + radius,
        maxY: y + radius,
      });

      for (const item of candidates) {
        const dist = distanceToCenter(x, y, item);
        if (dist < minDist && dist <= maxRadius) {
          minDist = dist;
          nearest = { id: item.id, distance: dist };
        }
      }

      radius *= 2;
    }

    return nearest;
  }
}
```

